Title: unstable/ai/Telemetry.AttributesWithPrefix
Category: type
Module Path: effect/unstable/ai/Telemetry
Export Kind: type
Category Tag: utility types
Stability: unstable

Description: Utility type for prefixing attribute names with a namespace. Transforms attribute keys by adding a prefix and formatting them according to OpenTelemetry conventions (camelCase to snake_case).

Example:
```ts
import type { Telemetry } from "effect/unstable/ai"

type RequestAttrs = {
  modelName: string
  maxTokens: number
}

type PrefixedAttrs = Telemetry.AttributesWithPrefix<
  RequestAttrs,
  "gen_ai.request"
>
// Results in: {
//   "gen_ai.request.model_name": string
//   "gen_ai.request.max_tokens": number
// }
```

