Title: unstable/ai/Prompt.prependSystem
Category: function
Module Path: effect/unstable/ai/Prompt
Export Kind: const
Category Tag: Combinators
Stability: unstable

Description: Creates a new prompt from the specified prompt with the provided text content prepended to the start of existing system message content. If no system message exists in the specified prompt, the provided content will be used to create a system message.

Example:
```ts
import { Prompt } from "effect/unstable/ai"

const systemPrompt = Prompt.make([{
  role: "system",
  content: "You are an expert in programming."
}])

const userPrompt = Prompt.make("Hello, world!")

const prompt = Prompt.concat(systemPrompt, userPrompt)

const replaced = Prompt.prependSystem(
  prompt,
  "You are a helpful assistant. "
)
// result content: "You are a helpful assistant. You are an expert in programming."
```

